import React from "react";

// For now, let's use some dummy data to see the UI.
// Later, we can connect this to your "Buy" actions!
const holdings = [
  {
    name: "BHARTIARTL",
    qty: 2,
    avg: 538.05,
    price: 541.15,
    net: "+0.58%",
    day: "+2.99%",
  },
  {
    name: "HDFCBANK",
    qty: 2,
    avg: 1383.4,
    price: 1522.35,
    net: "+10.04%",
    day: "+0.11%",
  },
  {
    name: "HINDUNILVR",
    qty: 1,
    avg: 2335.85,
    price: 2417.4,
    net: "+3.49%",
    day: "+1.85%",
  },
  {
    name: "INFY",
    qty: 1,
    avg: 1350.5,
    price: 1555.45,
    net: "+15.18%",
    day: "-1.60%",
  },
  {
    name: "ITC",
    qty: 5,
    avg: 202.0,
    price: 207.9,
    net: "+2.92%",
    day: "+0.80%",
  },
  {
    name: "KPITTECH",
    qty: 5,
    avg: 250.3,
    price: 266.45,
    net: "+6.45%",
    day: "+3.54%",
  },
];

const Holdings = () => {
  return (
    <div className="holdings-container">
      {/* Dynamic Section Header aligned identically to Orders and Dashboard layout */}
      <div className="holdings-header">
        <h6>Holdings ({holdings.length})</h6>
        <hr className="divider" />
      </div>

      <div className="table-container">
        <table className="holdings-table">
          <thead>
            <tr>
              <th>Instrument</th>
              <th>Qty.</th>
              <th>Avg. cost</th>
              <th>LTP</th>
              <th>Cur. val</th>
              <th>P&L</th>
              <th>Net chg.</th>
              <th>Day chg.</th>
            </tr>
          </thead>
          <tbody>
            {holdings.map((stock, index) => {
              const currValue = stock.price * stock.qty;
              const totalCost = stock.avg * stock.qty;
              const pnl = currValue - totalCost;
              const isProfit = stock.net.startsWith("+");
              const isDayProfit = stock.day.startsWith("+");

              return (
                <tr key={index}>
                  <td className="instrument-name">{stock.name}</td>
                  <td>{stock.qty}</td>
                  <td>{stock.avg.toFixed(2)}</td>
                  <td>{stock.price.toFixed(2)}</td>
                  <td>{currValue.toFixed(2)}</td>
                  <td className={pnl >= 0 ? "profit-text" : "loss-text"}>
                    {pnl.toFixed(2)}
                  </td>
                  <td className={isProfit ? "profit-text" : "loss-text"}>
                    {stock.net}
                  </td>
                  <td className={isDayProfit ? "profit-text" : "loss-text"}>
                    {stock.day}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Bottom Aggregations Row Layout */}
      <div className="holdings-summary-row">
        <div className="summary-col">
          <h5>
            29,875.<span>55</span>
          </h5>
          <p>Total investment</p>
        </div>
        <div className="summary-col">
          <h5>
            31,407.<span>00</span>
          </h5>
          <p>Current value</p>
        </div>
        <div className="summary-col">
          <h5 className="profit-text">1,531.45 (+5.13%)</h5>
          <p>P&L</p>
        </div>
      </div>
    </div>
  );
};

export default Holdings;
